B.ad7=s(["\xa7 4 KSchG","\xa7 43c BRAO"],t.s)
B.aSJ={sperrzeit_wahrscheinlich:0,ruhen_158:1}
B.aYI=new A.fp(B.aSJ,2,t.fF)
B.Zo=new A.mx("Fachanwalt f\xfcr Arbeitsrecht","K\xfcndigung oder Aufhebungsvertrag pr\xfcfen und die Abfindung verhandeln.","Ein Fachanwalt f\xfcr Arbeitsrecht kann deine K\xfcndigung oder den Aufhebungsvertrag pr\xfcfen, die Erfolgsaussichten einer K\xfcndigungsschutzklage einsch\xe4tzen und die Abfindung verhandeln. Wichtig ist die Drei-Wochen-Frist des \xa7 4 KSchG: Nach Zugang einer schriftlichen K\xfcndigung bleibt nur diese Zeit, um Klage zu erheben.","Qualifizierte Kanzleien findest du \xfcber das amtliche Anwaltsverzeichnis der Bundesrechtsanwaltskammer oder die Rechtsanwaltskammer deines Bezirks. ExitKompass vermittelt keine Kanzleien und verdient nichts an diesem Hinweis.",B.ad7,B.aYI)
B.cH={}
B.tZ=new A.fp(B.cH,0,t.fF)
B.Zp=new A.mx("Rechtsschutzversicherung pr\xfcfen","Bevor Beratungs- oder Prozesskosten entstehen.","Hast du eine Rechtsschutzversicherung mit Arbeitsrechtsschutz, \xfcbernimmt sie oft Anwalts- und Gerichtskosten. Pr\xfcfe die Wartezeit (meist drei Monate) und ob der Streitfall schon vor Vertragsbeginn angelegt war. Vor dem ersten Anwaltstermin lohnt sich eine Deckungsanfrage.","Steht in deiner Police oder erf\xe4hrst du direkt bei deiner Versicherung. ExitKompass empfiehlt keinen bestimmten Anbieter.",B.bL,B.tZ)
B.aJv=s(["BerHG","\xa7\xa7 114 ff. ZPO"],t.s)
B.Zm=new A.mx("Beratungs- und Prozesskostenhilfe","Wenn anwaltliche Hilfe finanziell schwerf\xe4llt.","Mit geringem Einkommen kannst du beim \xf6rtlichen Amtsgericht einen Beratungshilfeschein f\xfcr eine Erstberatung beantragen (Eigenanteil rund 15 \u20ac). F\xfcr ein Gerichtsverfahren gibt es Prozesskostenhilfe. Beides beantragst du beim Amtsgericht deines Wohnorts.","Rechtsantragstelle des Amtsgerichts am Wohnort.",B.aJv,B.tZ)
B.aOb=s(["\xa7 38 SGB III","\xa7 141 SGB III"],t.s)
B.aSQ={sperrzeit_eigenkuendigung:0,sperrzeit_wahrscheinlich:1,ruhen_158:2,alg_gedeckelt:3}
B.aYD=new A.fp(B.aSQ,4,t.fF)
B.Zn=new A.mx("Agentur f\xfcr Arbeit: fr\xfch melden","Sobald du von der Beendigung erf\xe4hrst.","Melde dich sp\xe4testens drei Tage nach Kenntnis vom Ende arbeitsuchend \u2013 bei mehr als drei Monaten Vorlauf sp\xe4testens drei Monate vorher (\xa7 38 SGB III), sonst droht eine Minderung. Zum ersten Tag der Besch\xe4ftigungslosigkeit meldest du dich arbeitslos (\xa7 141 SGB III). Beides geht online oder pers\xf6nlich; die Agentur ber\xe4t auch zu ALG und Weiterbildung.","Agentur f\xfcr Arbeit \u2013 online oder in der \xf6rtlichen Dienststelle.",B.aOb,B.aYD)
B.aNc=s(["\xa7 188 SGB V","\xa7 5 SGB V"],t.s)
B.aSS={kv_luecke:0}
B.aYA=new A.fp(B.aSS,1,t.fF)
B.Zl=new A.mx("Krankenversicherung kl\xe4ren","F\xfcr Monate ohne Gehalt und ohne ALG.","W\xe4hrend des ALG-Bezugs bist du in der Regel \xfcber die Agentur versichert. In L\xfcckenmonaten ohne Gehalt und ohne ALG musst du deinen Versicherungsschutz selbst sichern \u2013 etwa \xfcber die freiwillige Weiterversicherung oder die Familienversicherung. Melde dich fr\xfch bei deiner Krankenkasse; r\xfcckwirkende L\xfccken werden teuer. Privatversicherte haben eigene Regeln.","Deine gesetzliche Krankenkasse bzw. dein privater Versicherer.",B.aNc,B.aYA)
B.aKt=s(["\xa7 102 BetrVG"],t.s)
B.Zk=new A.mx("Betriebsrat und Gewerkschaft","Wenn es einen Betriebsrat oder eine Gewerkschaft gibt.","Der Betriebsrat muss vor jeder K\xfcndigung angeh\xf6rt werden (\xa7 102 BetrVG) \u2013 eine unterbliebene Anh\xf6rung macht die K\xfcndigung unwirksam. Bist du Gewerkschaftsmitglied, geh\xf6ren arbeitsrechtliche Beratung und Rechtsschutz meist zum Mitgliedsbeitrag.","Betriebsrat im Unternehmen; deine Gewerkschaft.",B.aKt,B.tZ)
B.aLO=s([B.Zo,B.Zp,B.Zm,B.Zn,B.Zl,B.Zk],t.jQ)
B.b_q=new A.jU(0,"finanzen")
B.b_r=new A.jU(1,"verhandeln")
B.b_s=new A.jU(2,"bewerbung")
B.b_t=new A.jU(3,"informieren")
B.aLQ=s([B.b_q,B.b_r,B.b_s,B.b_t],A.a6("p<jU>"))
B.aLR=s(["Mon","Tue","Wed","Thu","Fri","Sat","Sun"],t.s)
B.eN=new A.lW(0,"leading")
B.d9=new A.lW(1,"title")
B.eO=new A.lW(2,"subtitle")
B.ic=new A.lW(3,"trailing")
B.aLW=s([B.eN,B.d9,B.eO,B.ic],A.a6("p<lW>"))
