B.UZ=new A.tF(2,"chromium")
B.aM6=s([B.UX,B.UY,B.UZ,B.eo],A.a6("p<tF>"))
B.aMa=s([B.f6,B.er,B.iE,B.f7],A.a6("p<mk>"))
B.RE=new A.cM("Grundsatz","Einen allgemeinen gesetzlichen Anspruch auf eine Abfindung gibt es in Deutschland nicht. Eine Abfindung ist meist das Ergebnis einer Einigung \u2013 etwa in einem Vergleich vor dem Arbeitsgericht oder in einem Aufhebungsvertrag.")
B.Rf=new A.cM("Die wichtigsten Ausnahmen","Ein Anspruch kann sich ergeben aus einem Abfindungsangebot bei betriebsbedingter K\xfcndigung (\xa7 1a KSchG), aus einem Sozialplan (\xa7\xa7 112, 112a BetrVG), aus einem Nachteilsausgleich (\xa7 113 BetrVG) oder aus einem gerichtlichen Aufl\xf6sungsurteil (\xa7\xa7 9, 10 KSchG).")
B.Rb=new A.cM("Warum trotzdem oft gezahlt wird","Auch ohne Anspruch bieten viele Arbeitgeber eine Abfindung an, um das Kosten- und Prozessrisiko einer K\xfcndigungsschutzklage zu vermeiden. Genau darin liegt der Verhandlungsspielraum.")
B.aJt=s([B.RE,B.Rf,B.Rb],t.aX)
B.aM8=s(["\xa7 1a KSchG","\xa7\xa7 9, 10 KSchG","\xa7\xa7 112, 112a, 113 BetrVG"],t.s)
B.RN=new A.hP(B.ii,"Habe ich Anspruch auf eine Abfindung?","Meistens nein \u2013 aber es gibt wichtige Ausnahmen und viel Verhandlungsspielraum.",B.aJt,B.aM8)
B.Rj=new A.cM("Die Faustformel","Als grobe Orientierung gilt: ein halbes Bruttomonatsgehalt je Jahr der Betriebszugeh\xf6rigkeit. Diese Gr\xf6\xdfe nennt auch \xa7 1a KSchG als Regelabfindung. Sie ist ein Anhaltspunkt, keine Obergrenze und kein Anspruch.")
B.R9=new A.cM("Was die H\xf6he beeinflusst","Wie gut die Erfolgsaussichten einer K\xfcndigungsschutzklage sind, wie dringend der Arbeitgeber die Trennung braucht, die Dauer der Betriebszugeh\xf6rigkeit und die Lage am Arbeitsmarkt wirken sich auf die tats\xe4chliche H\xf6he aus.")
B.Re=new A.cM("Mehr als nur Geld","Verhandelbar sind neben dem Betrag oft auch die Zeugnisnote, eine bezahlte Freistellung, der Verzicht auf R\xfcckzahlungsklauseln, der Auszahlungszeitpunkt (steuerlich relevant) und Leistungen wie Outplacement.")
B.aPV=s([B.Rj,B.R9,B.Re],t.aX)
B.aND=s(["\xa7 1a KSchG"],t.s)
B.RF=new A.hP(B.ii,"Wie hoch f\xe4llt eine Abfindung \xfcblicherweise aus?","Die Faustformel als Orientierung \u2013 und warum sie nur ein Startpunkt ist.",B.aPV,B.aND)
B.Rw=new A.cM("Prozessrisiko als Druckmittel","Eine fristgerechte K\xfcndigungsschutzklage h\xe4lt den Rechtsweg offen. F\xfcr den Arbeitgeber bedeutet ein laufendes Verfahren Unsicherheit, Zeit und Kosten \u2013 das erh\xf6ht die Bereitschaft, sich per Vergleich zu einigen.")
B.Rx=new A.cM("Auszahlung ins Folgejahr","Der Zeitpunkt der Auszahlung kann die Steuerlast ver\xe4ndern (Progression, F\xfcnftelregelung). Ob sich eine Verschiebung lohnt, l\xe4sst sich im Rechner dieser App durchspielen.")
B.Rn=new A.cM("Nicht unter Druck unterschreiben","F\xfcr einen Aufhebungsvertrag gibt es keine gesetzliche Bedenkzeit und kein Widerrufsrecht. Einmal unterschrieben, gilt er \u2013 deshalb ist Ruhe vor der Unterschrift wichtiger als Tempo.")
B.aFU=s([B.Rw,B.Rx,B.Rn],t.aX)
B.aNF=s(["\xa7 34 EStG","\xa7 4 KSchG"],t.s)
B.RM=new A.hP(B.ii,"Verhandlungshebel bei Abfindung und Aufhebung","Prozessrisiko, Fristen und Timing sind deine st\xe4rksten Argumente.",B.aFU,B.aNF)
B.Rl=new A.cM("Vertrauen \u2192 Interdependenz","Vertrauen ist subjektiv und braucht Zeit; es garantiert keine Gegenleistung. Wirksamer ist es, die Anreize zu koppeln: Wenn beide Seiten erkennen, dass Zusammenarbeit im eigenen Interesse liegt, tr\xe4gt die Einigung von selbst.")
B.Rr=new A.cM("Zuh\xf6ren \u2192 proaktiv fragen","Blo\xdfes (auch aktives) Zuh\xf6ren ist reaktiv. Wer die Verhandlung f\xfchren will, stellt zuerst Fragen und lenkt so das Gespr\xe4ch dorthin, wo am meisten zu lernen ist.")
B.RB=new A.cM("Transparent \u2192 durchscheinend auf der Sache","Bei Beziehung und Kommunikation darfst du offen sein. Auf der Sachebene gilt: nur so viel preisgeben, wie n\xf6tig ist, damit die Gegenseite eine Einigung anstrebt \u2013 nicht mehr.")
B.R8=new A.cM("Nett & fair \u2192 positiv und vern\xfcnftig",'Nettigkeit kann als Schw\xe4che gelesen werden. Sei stattdessen positiv, aber nicht naiv, und statt \u201esubjektiv fair" lieber \u201evern\xfcnftig": ein Vorschlag, der im Wertesystem beider Seiten nachvollziehbar ist.')
B.Rc=new A.cM("Treu zur Person \u2192 treu zum Prozess","Bleib dem fairen Verhandlungsprozess verpflichtet, nicht bedingungslos der Gegenseite. Und verpflichte dich dem guten Prozess \u2013 nicht einem bestimmten Ergebnis, das du ohnehin nicht garantieren kannst.")
B.Rg=new A.cM("Das eigentliche Werkzeug: bewusster Machtverzicht",'Auf Machtspiele zu verzichten ist keine Schw\xe4che, sondern eine strategische Entscheidung, die oft zu besseren Ergebnissen f\xfchrt. (Nach \u201eGetting to Yes" von Fisher/Ury.)')
B.aMB=s([B.Rl,B.Rr,B.RB,B.R8,B.Rc,B.Rg],t.aX)
B.aPz=s(["Getting to Yes (Fisher/Ury)"],t.s)
B.RO=new A.hP(B.ii,"Sieben Mythen der Win-win-Verhandlung","Nett, fair und vertrauensvoll allein macht dich in der Verhandlung nicht stark \u2013 hier die wirksameren Strategien.",B.aMB,B.aPz)
B.Rh=new A.cM("Zwei Voraussetzungen","Das K\xfcndigungsschutzgesetz (KSchG) gilt, wenn das Arbeitsverh\xe4ltnis l\xe4nger als sechs Monate bestanden hat und im Betrieb in der Regel mehr als zehn Arbeitnehmer besch\xe4ftigt sind (Kleinbetriebsklausel).")
B.Rd=new A.cM("Wenn es greift","Dann braucht eine ordentliche K\xfcndigung einen anerkannten Grund \u2013 betriebsbedingt, verhaltensbedingt oder personenbedingt \u2013 und muss sozial gerechtfertigt sein.")
B.Rq=new A.cM("Auch im Kleinbetrieb","Selbst ohne KSchG darf eine K\xfcndigung nicht sitten- oder treuwidrig sein, und es gelten Formvorschriften, Fristen und der Sonderk\xfcndigungsschutz.")
B.aNA=s([B.Rh,B.Rd,B.Rq],t.aX)
B.azA=s(["\xa7 1 KSchG","\xa7 23 KSchG"],t.s)
B.RJ=new A.hP(B.kn,"Gilt der K\xfcndigungsschutz f\xfcr mich?","Das K\xfcndigungsschutzgesetz greift erst ab bestimmten Voraussetzungen.",B.aNA,B.azA)
B.RC=new A.cM("Nur schriftlich","Eine K\xfcndigung muss schriftlich mit eigenh\xe4ndiger Unterschrift erfolgen (\xa7 623 BGB). Eine K\xfcndigung per E-Mail, SMS oder Messenger ist unwirksam.")
B.Rv=new A.cM("Betriebsrat anh\xf6ren","Gibt es einen Betriebsrat, muss er vor jeder K\xfcndigung angeh\xf6rt werden (\xa7 102 BetrVG). Ohne ordnungsgem\xe4\xdfe Anh\xf6rung ist die K\xfcndigung unwirksam.")
B.RA=new A.cM("K\xfcndigungsfristen","Die gesetzlichen Fristen richten sich nach \xa7 622 BGB und verl\xe4ngern sich f\xfcr Arbeitgeberk\xfcndigungen mit der Dauer der Betriebszugeh\xf6rigkeit. Im Vertrag oder Tarifvertrag k\xf6nnen abweichende Fristen stehen.")
B.aMd=s([B.RC,B.Rv,B.RA],t.aX)
B.aNM=s(["\xa7 623 BGB","\xa7 622 BGB","\xa7 102 BetrVG"],t.s)
B.RI=new A.hP(B.kn,"Formfehler und Fristen: Wann eine K\xfcndigung unwirksam ist","Schriftform, Unterschrift, Betriebsratsanh\xf6rung \u2013 Formfehler z\xe4hlen.",B.aMd,B.aNM)
B.Ri=new A.cM("Drei Wochen ab Zugang","Wer sich gegen eine K\xfcndigung wehren will, muss innerhalb von drei Wochen ab Zugang der schriftlichen K\xfcndigung K\xfcndigungsschutzklage beim Arbeitsgericht erheben (\xa7 4 KSchG).")
B.Rm=new A.cM("Was nach Fristablauf passiert","Wird die Frist vers\xe4umt, gilt die K\xfcndigung grunds\xe4tzlich als von Anfang an wirksam (\xa7 7 KSchG) \u2013 unabh\xe4ngig davon, ob sie eigentlich angreifbar gewesen w\xe4re.")
B.Rt=new A.cM("Auch als Verhandlungsweg","Die Klage dient nicht nur der Weiterbesch\xe4ftigung. Viele Verfahren enden mit einem Vergleich, in dem eine Abfindung vereinbart wird.")
B.a13=s([B.Ri,B.Rm,B.Rt],t.aX)
B.aK4=s(["\xa7 4 KSchG","\xa7 7 KSchG"],t.s)
B.RL=new A.hP(B.kn,"Die 3-Wochen-Frist f\xfcr die K\xfcndigungsschutzklage","Der wichtigste Termin \xfcberhaupt \u2013 nach Ablauf gilt die K\xfcndigung als wirksam.",B.a13,B.aK4)
B.Rs=new A.cM("Wann melden?","Wer wei\xdf, dass sein Arbeitsverh\xe4ltnis endet, muss sich sp\xe4testens drei Monate vor dem Ende arbeitsuchend melden. Liegen zwischen Kenntnis und Ende weniger als drei Monate, muss die Meldung innerhalb von drei Tagen nach Kenntnis erfolgen (\xa7 38 SGB III).")
B.Ro=new A.cM("Wie melden?","Die Arbeitsuchendmeldung ist telefonisch, pers\xf6nlich oder online \xfcber die Website der Bundesagentur f\xfcr Arbeit m\xf6glich. Sie ist etwas anderes als die sp\xe4tere Arbeitslosmeldung.")
B.Rp=new A.cM("Warum das wichtig ist","Eine versp\xe4tete Meldung kann als Meldevers\xe4umnis eine Sperrzeit nach sich ziehen (\xa7 159 SGB III) und damit den ALG-Bezug verk\xfcrzen.")
B.aMK=s([B.Rs,B.Ro,B.Rp],t.aX)
B.apa=s(["\xa7 38 SGB III","\xa7 159 SGB III"],t.s)
